import React, { useState, useEffect, useCallback } from 'react';
import api from '../services/api';

const STATUS_CFG = {
  PENDING:   { color: '#C9A84C', bg: 'rgba(201,168,76,0.12)',  icon: '⏳' },
  MATCHED:   { color: '#4CAF82', bg: 'rgba(76,175,130,0.12)',  icon: '🚖' },
  ACTIVE:    { color: '#5B93E8', bg: 'rgba(91,147,232,0.12)',  icon: '🛣️' },
  COMPLETED: { color: '#4CAF82', bg: 'rgba(76,175,130,0.08)',  icon: '✅' },
  CANCELLED: { color: '#E85555', bg: 'rgba(232,85,85,0.08)',   icon: '✕'  },
};

export default function AdminPanel() {
  const [tab, setTab]     = useState('rides');
  const [rides,   setRides]   = useState([]);
  const [users,   setUsers]   = useState([]);
  const [drivers, setDrivers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [msg,     setMsg]     = useState('');

  const fetchAll = useCallback(async () => {
    setLoading(true);
    try {
      const [ridesR, usersR, driversR] = await Promise.all([
        api.get('/api/fare/rides'),
        api.get('/api/auth/users'),
        api.get('/api/drivers'),
      ]);
      setRides(Array.isArray(ridesR.data) ? ridesR.data.sort((a,b) => new Date(b.requestTime) - new Date(a.requestTime)) : []);
      setUsers(Array.isArray(usersR.data) ? usersR.data : []);
      setDrivers(Array.isArray(driversR.data) ? driversR.data : []);
    } catch (err) { console.error(err); }
    setLoading(false);
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);

  const updateRideStatus = async (rideId, status) => {
    try {
      await api.patch(`/api/fare/rides/${rideId}/status?status=${status}`);
      setRides(prev => prev.map(r => r.id === rideId ? { ...r, status } : r));
      setMsg(`✓ Ride #${rideId} updated to ${status}`);
    } catch { setMsg('✗ Error updating ride status.'); }
  };

  const toggleUser = async (userId, isActive) => {
    try {
      await api.patch(`/api/auth/users/${userId}/${isActive ? 'deactivate' : 'activate'}`);
      setUsers(prev => prev.map(u => u.id === userId ? { ...u, active: !isActive } : u));
      setMsg(`✓ User #${userId} ${isActive ? 'deactivated' : 'activated'}.`);
    } catch { setMsg('✗ Error updating user.'); }
  };

  const updateDriverStatus = async (driverId, status) => {
    try {
      await api.patch(`/api/drivers/${driverId}/status?status=${status}`);
      setDrivers(prev => prev.map(d => d.id === driverId ? { ...d, status } : d));
      setMsg(`✓ Driver #${driverId} status set to ${status}`);
    } catch { setMsg('✗ Error updating driver.'); }
  };

  const TABS = [
    { id: 'rides',   label: `🚖 All Rides (${rides.length})` },
    { id: 'users',   label: `👤 Users (${users.length})` },
    { id: 'drivers', label: `🧑‍✈️ Drivers (${drivers.length})` },
    { id: 'stats',   label: '📊 Stats' },
  ];

  const completedRides = rides.filter(r => r.status === 'COMPLETED');
  const pendingRides   = rides.filter(r => r.status === 'PENDING');
  const totalRevenue   = completedRides.reduce((s, r) => s + (r.finalFare || r.estimatedFare || 0), 0);

  return (
    <>
      {msg && (
        <div className={`alert ${msg.startsWith('✓') ? 'alert-success' : 'alert-error'}`}
          style={{ marginBottom: 12 }}>
          {msg}
          <button onClick={() => setMsg('')} style={{ float: 'right', background: 'none', border: 'none', cursor: 'pointer', color: 'inherit', fontWeight: 700 }}>✕</button>
        </div>
      )}

      {/* Tab header */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' }}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)} style={{
            padding: '8px 16px', borderRadius: 10, fontSize: 12, fontWeight: 700,
            border: tab === t.id ? '1px solid var(--gold)' : '1px solid var(--border)',
            background: tab === t.id ? 'rgba(201,168,76,0.12)' : 'none',
            color: tab === t.id ? 'var(--gold)' : 'var(--text-muted)',
            cursor: 'pointer',
          }}>{t.label}</button>
        ))}
        <button className="btn-secondary" onClick={fetchAll} disabled={loading}
          style={{ marginLeft: 'auto', padding: '8px 16px', fontSize: 12 }}>
          {loading ? <span className="spinner" style={{ width: 12, height: 12 }} /> : '↻ Refresh'}
        </button>
      </div>

      {/* ── RIDES TAB ───────────────────────────────────────────── */}
      {tab === 'rides' && (
        <div className="panel">
          <div className="panel-header">
            <h3>🚖 All Ride Requests</h3>
            <span className="badge">{rides.length} total</span>
          </div>
          <div className="panel-body">
            {rides.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-muted)' }}>
                <div style={{ fontSize: 40, marginBottom: 10 }}>📭</div>
                No ride requests yet.
              </div>
            ) : (
              <div style={{ display: 'grid', gap: 10 }}>
                {rides.map(r => {
                  const cfg = STATUS_CFG[r.status] || STATUS_CFG.PENDING;
                  return (
                    <div key={r.id} style={{
                      padding: '14px 16px', background: 'var(--bg-3)',
                      borderRadius: 12, border: `1px solid ${cfg.bg}`,
                    }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                        <div>
                          <div style={{ fontWeight: 700, fontSize: 13 }}>
                            {cfg.icon} Ride #{r.id}
                          </div>
                          <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 2 }}>
                            Passenger #{r.passengerId}
                            {r.driverId ? ` · Driver #${r.driverId}` : ' · No driver yet'}
                            · {r.vehicleType} · {new Date(r.requestTime).toLocaleString('en-IN', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' })}
                          </div>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                          <span style={{ fontWeight: 700, color: 'var(--gold)', fontSize: 13 }}>
                            ₹{(r.finalFare || r.estimatedFare || 0).toFixed(0)}
                          </span>
                          <span style={{ padding: '3px 8px', borderRadius: 99, fontSize: 11, fontWeight: 700, background: cfg.bg, color: cfg.color }}>
                            {r.status}
                          </span>
                        </div>
                      </div>
                      {/* Admin actions */}
                      {['PENDING', 'MATCHED', 'ACTIVE'].includes(r.status) && (
                        <div style={{ display: 'flex', gap: 6, marginTop: 6 }}>
                          {r.status === 'PENDING' && (
                            <button onClick={() => updateRideStatus(r.id, 'CANCELLED')}
                              style={{ padding: '4px 10px', borderRadius: 7, fontSize: 11, border: '1px solid rgba(232,85,85,0.4)', background: 'rgba(232,85,85,0.08)', color: '#E85555', cursor: 'pointer' }}>
                              Cancel
                            </button>
                          )}
                          {r.status === 'MATCHED' && (
                            <button onClick={() => updateRideStatus(r.id, 'ACTIVE')}
                              style={{ padding: '4px 10px', borderRadius: 7, fontSize: 11, border: '1px solid rgba(91,147,232,0.4)', background: 'rgba(91,147,232,0.08)', color: '#5B93E8', cursor: 'pointer' }}>
                              → Active
                            </button>
                          )}
                          {r.status === 'ACTIVE' && (
                            <button onClick={() => updateRideStatus(r.id, 'COMPLETED')}
                              style={{ padding: '4px 10px', borderRadius: 7, fontSize: 11, border: '1px solid rgba(76,175,130,0.4)', background: 'rgba(76,175,130,0.08)', color: '#4CAF82', cursor: 'pointer' }}>
                              ✓ Complete
                            </button>
                          )}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── USERS TAB ───────────────────────────────────────────── */}
      {tab === 'users' && (
        <div className="panel">
          <div className="panel-header">
            <h3>👤 All Users</h3>
            <span className="badge">{users.length} registered</span>
          </div>
          <div className="panel-body">
            {users.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-muted)' }}>No users.</div>
            ) : (
              <div style={{ display: 'grid', gap: 10 }}>
                {users.map(u => (
                  <div key={u.id} style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    padding: '12px 16px', background: 'var(--bg-3)', borderRadius: 12,
                    border: '1px solid var(--border)', opacity: u.active ? 1 : 0.6,
                  }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 13 }}>{u.fullName}</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 2 }}>
                        {u.email} · {u.role}
                        {u.driverId ? ` · Driver #${u.driverId}` : ''}
                      </div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{
                        padding: '3px 8px', borderRadius: 99, fontSize: 11, fontWeight: 700,
                        background: u.active ? 'rgba(76,175,130,0.12)' : 'rgba(232,85,85,0.12)',
                        color: u.active ? '#4CAF82' : '#E85555',
                      }}>
                        {u.active ? '● Active' : '● Inactive'}
                      </span>
                      <button onClick={() => toggleUser(u.id, u.active)} style={{
                        padding: '4px 10px', borderRadius: 7, fontSize: 11, cursor: 'pointer',
                        border: '1px solid var(--border)', background: 'none', color: 'var(--text-muted)',
                      }}>
                        {u.active ? 'Deactivate' : 'Activate'}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── DRIVERS TAB ─────────────────────────────────────────── */}
      {tab === 'drivers' && (
        <div className="panel">
          <div className="panel-header">
            <h3>🧑‍✈️ All Drivers</h3>
            <span className="badge">{drivers.length} registered</span>
          </div>
          <div className="panel-body">
            {drivers.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-muted)' }}>
                No drivers. Add them in Driver Matching.
              </div>
            ) : (
              <div style={{ display: 'grid', gap: 10 }}>
                {drivers.map(d => (
                  <div key={d.id} style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    padding: '12px 16px', background: 'var(--bg-3)', borderRadius: 12, border: '1px solid var(--border)',
                  }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 13 }}>🧑‍✈️ {d.driverName}</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 2 }}>
                        {d.vehicleType} · {d.vehicleNumber} · {d.zone} · ★ {d.rollingAverageRating?.toFixed(1)}
                        {d.warningFlagged && ' · ⚠ Warned'}
                      </div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{d.contactNumber}</div>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{
                        padding: '3px 8px', borderRadius: 99, fontSize: 11, fontWeight: 700,
                        background: d.status === 'AVAILABLE' ? 'rgba(76,175,130,0.12)' : 'rgba(201,168,76,0.12)',
                        color: d.status === 'AVAILABLE' ? '#4CAF82' : '#C9A84C',
                      }}>
                        {d.status}
                      </span>
                      <select defaultValue="" onChange={e => { if (e.target.value) updateDriverStatus(d.id, e.target.value); }}
                        style={{ padding: '4px 8px', borderRadius: 7, fontSize: 11, border: '1px solid var(--border)', background: 'var(--bg-3)', color: 'var(--text-pri)', cursor: 'pointer' }}>
                        <option value="">Change…</option>
                        {['AVAILABLE', 'BUSY', 'OFFLINE'].map(s => <option key={s} value={s}>{s}</option>)}
                      </select>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      {/* ── STATS TAB ───────────────────────────────────────────── */}
      {tab === 'stats' && (
        <>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px,1fr))', gap: 14, marginBottom: 20 }}>
            {[
              { label: 'Total Rides',    value: rides.length,          color: 'var(--gold)'  },
              { label: 'Pending',        value: pendingRides.length,   color: '#C9A84C'      },
              { label: 'Completed',      value: completedRides.length, color: '#4CAF82'      },
              { label: 'Total Revenue',  value: `₹${totalRevenue.toFixed(0)}`, color: 'var(--gold)' },
              { label: 'Total Users',    value: users.length,          color: '#5B93E8'      },
              { label: 'Total Drivers',  value: drivers.length,        color: '#C9A84C'      },
              { label: 'Available Drivers', value: drivers.filter(d => d.status === 'AVAILABLE').length, color: '#4CAF82' },
            ].map(c => (
              <div key={c.label} className="stat-card" style={{ padding: '16px' }}>
                <div style={{ fontSize: '0.6rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.1em', color: 'var(--text-muted)', marginBottom: 8 }}>{c.label}</div>
                <div style={{ fontFamily: 'Playfair Display', fontSize: '1.9rem', fontWeight: 700, color: c.color, lineHeight: 1 }}>{c.value}</div>
              </div>
            ))}
          </div>
        </>
      )}
    </>
  );
}
